package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves the processed output to the specified file.
// Returns the stdout of the jq processing pipeline (formatted JSON content) and any error encountered.
// Note: Avoids shell usage entirely to prevent injection risks and enables proper output capture.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate required parameters are non-empty
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Build aliyun CLI command with direct argument passing (no shell)
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build jq command with hardcoded safe filter
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr streams separately for diagnostics
	var aliyunErrBuf, jqErrBuf bytes.Buffer
	cmdAliyun.Stderr = &aliyunErrBuf
	cmdJq.Stderr = &jqErrBuf

	// Pipe aliyun stdout directly to jq stdin
	aliyunStdout, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	cmdJq.Stdin = aliyunStdout

	// Capture jq's processed stdout
	jqStdout, err := cmdJq.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}

	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := cmdJq.Start(); err != nil {
		cmdAliyun.Wait() // Cleanup aliyun process
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read entire processed output from jq
	outputBytes, readErr := io.ReadAll(jqStdout)

	// Wait for both commands to complete
	aliyunErr := cmdAliyun.Wait()
	jqErr := cmdJq.Wait()

	// Handle pipeline errors with detailed diagnostics
	if aliyunErr != nil || jqErr != nil || readErr != nil {
		errorMsg := "SLB query pipeline failed"
		if aliyunErrBuf.Len() > 0 {
			errorMsg += fmt.Sprintf("\naliyun stderr: %s", aliyunErrBuf.String())
		}
		if jqErrBuf.Len() > 0 {
			errorMsg += fmt.Sprintf("\njq stderr: %s", jqErrBuf.String())
		}
		if len(outputBytes) > 0 {
			errorMsg += fmt.Sprintf("\npartial output: %s", string(outputBytes))
		}
		if readErr != nil {
			errorMsg += fmt.Sprintf("\nread error: %v", readErr)
		}
		return string(outputBytes), fmt.Errorf(
			"%s; aliyun exit error: %v, jq exit error: %v",
			errorMsg,
			aliyunErr,
			jqErr,
		)
	}

	// Write processed output to specified file
	if err := os.WriteFile(outputFile, outputBytes, 0644); err != nil {
		return string(outputBytes), fmt.Errorf("failed to write output to file %q: %w", outputFile, err)
	}

	return string(outputBytes), nil
}

