package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI to fetch SLB information for the specified load balancer name,
// processes the JSON output using jq to extract load balancer entries, writes the result to outputFile,
// and returns the processed output as a string along with any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Execute aliyun command to retrieve SLB information
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	aliyunOutput, err := cmdAliyun.Output()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w; stderr: %s", err, aliyunStderr.String())
	}

	// Process JSON output using jq filter
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	cmdJq.Stdin = bytes.NewReader(aliyunOutput)
	var jqStderr bytes.Buffer
	cmdJq.Stderr = &jqStderr
	jqOutput, err := cmdJq.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w; stderr: %s", err, jqStderr.String())
	}

	// Write processed output to specified file
	if err := os.WriteFile(outputFile, jqOutput, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

func main() {
	// Required for package main to be compilable and executable.
	// This implementation provides the QuerySLBAndExport function for external use.
	// In practice, call QuerySLBAndExport with desired parameters from your application logic.
}

