// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves the formatted result to the specified file.
// Returns the stdout of the command pipeline (jq-formatted output) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate required parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Construct aliyun command with explicit arguments (no shell)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Construct jq command with the required filter
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Buffers to capture stderr from both commands (handled safely by Go runtime)
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Connect aliyun stdout to jq stdin
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	jqCmd.Stdin = aliyunOut

	// Capture jq stdout for return value and file writing
	jqOut, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill()
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read jq's processed output
	outputBytes, err := io.ReadAll(jqOut)
	if err != nil {
		aliyunCmd.Process.Kill()
		jqCmd.Process.Kill()
		aliyunCmd.Wait()
		jqCmd.Wait()
		return "", fmt.Errorf("failed to read jq output: %w", err)
	}

	// Wait for both commands to complete
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	// Handle command execution errors
	if aliyunErr != nil || jqErr != nil {
		stderrMsg := strings.TrimSpace(aliyunStderr.String() + jqStderr.String())
		var errMsg strings.Builder
		errMsg.WriteString("SLB query pipeline failed")
		if stderrMsg != "" {
			errMsg.WriteString(": ")
			errMsg.WriteString(stderrMsg)
		}
		if aliyunErr != nil && jqErr != nil {
			errMsg.WriteString(fmt.Sprintf(" (aliyun exit error: %v, jq exit error: %v)", aliyunErr, jqErr))
		} else if aliyunErr != nil {
			errMsg.WriteString(fmt.Sprintf(" (aliyun exit error: %v)", aliyunErr))
		} else {
			errMsg.WriteString(fmt.Sprintf(" (jq exit error: %v)", jqErr))
		}
		return string(outputBytes), fmt.Errorf("%s", errMsg.String())
	}

	// Write processed output to specified file
	if err := os.WriteFile(outputFile, outputBytes, 0644); err != nil {
		return string(outputBytes), fmt.Errorf("failed to write output file: %w", err)
	}

	return string(outputBytes), nil
}

