package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// runCommand executes the given command and returns stdout, stderr, and error.
// This helper ensures clean separation of streams without shell interpretation.
func runCommand(cmd *exec.Cmd) ([]byte, []byte, error) {
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	err := cmd.Run()
	return stdout.Bytes(), stderr.Bytes(), err
}

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves the filtered result to the specified file.
// Returns the combined stderr output from both commands (aliyun and jq) and any error.
// Security notes:
// - Avoids shell entirely to eliminate command injection risks
// - Validates inputs for null bytes and empty values
// - Uses direct argument passing instead of string interpolation
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs to prevent path traversal vectors and invalid execution
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}
	if strings.Contains(loadBalancerName, "\x00") || strings.Contains(outputFile, "\x00") {
		return "", fmt.Errorf("input parameters contain null bytes")
	}

	// Execute aliyun command with direct argument passing (no shell)
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, aliyunStderr, err := runCommand(cmdAliyun)
	combinedStderr := string(aliyunStderr)

	if err != nil {
		return combinedStderr, fmt.Errorf("aliyun command failed: %w", err)
	}

	// Process JSON output with jq using aliyun's stdout as input
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	cmdJq.Stdin = bytes.NewReader(aliyunStdout)
	jqStdout, jqStderr, err := runCommand(cmdJq)
	combinedStderr += string(jqStderr)

	if err != nil {
		return combinedStderr, fmt.Errorf("jq command failed: %w", err)
	}

	// Write processed output directly to file (no shell redirection)
	if err := os.WriteFile(outputFile, jqStdout, 0644); err != nil {
		return combinedStderr, fmt.Errorf("failed to write output file: %w", err)
	}

	return combinedStderr, nil
}

