		return "", fmt.Errorf("jq command failed: %w; stderr: %s", errJq, jqErrBuf.String())
	}

	// Write processed output to specified file
	if err := os.WriteFile(outputFile, jqOutBuf.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file %q: %w", outputFile, err)
	}

