package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves the formatted result to the specified file.
// Returns combined stderr output from both commands and any execution error.
// Security note: Avoids shell injection by using direct command execution with argument passing.
// Caller must validate outputFile path safety to prevent path traversal risks.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate required parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create output file (fails fast on permission/path issues)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()

	// Initialize commands with direct argument passing (NO shell interpolation)
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun stdout to jq stdin via pipe
	aliyunStdout, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun stdout: %w", err)
	}
	cmdJq.Stdin = aliyunStdout
	cmdJq.Stdout = outFile // Directly write jq output to file

	// Capture stderr from both commands separately
	var aliyunErrBuf, jqErrBuf bytes.Buffer
	cmdAliyun.Stderr = &aliyunErrBuf
	cmdJq.Stderr = &jqErrBuf

	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return combineStderr(&aliyunErrBuf, &jqErrBuf), 
			fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := cmdJq.Start(); err != nil {
		// Clean up aliyun process on jq startup failure
		cmdAliyun.Process.Kill()
		cmdAliyun.Wait()
		return combineStderr(&aliyunErrBuf, &jqErrBuf), 
			fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for commands to complete (aliyun first to avoid pipe deadlock)
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// Combine stderr outputs for diagnostics
	combinedStderr := combineStderr(&aliyunErrBuf, &jqErrBuf)

	// Report errors while preserving stderr context
	if errAliyun != nil || errJq != nil {
		return combinedStderr, fmt.Errorf(
			"command pipeline failed; aliyun error: %v, jq error: %v; stderr: %s",
			errAliyun, errJq, combinedStderr,
		)
	}

	return combinedStderr, nil
}

// combineStderr safely concatenates stderr outputs from both commands
func combineStderr(buf1, buf2 *bytes.Buffer) string {
	return buf1.String() + buf2.String()
}

