// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns combined stderr output from commands (for warnings/errors) and any execution error.
// Security note: Avoids shell injection by using direct command execution with argument separation.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate required parameters to prevent runtime errors
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName must not be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile must not be empty")
	}

	// Execute aliyun CLI command with direct argument passing (no shell)
	var aliyunStdout, aliyunStderr bytes.Buffer
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	cmdAliyun.Stdout = &aliyunStdout
	cmdAliyun.Stderr = &aliyunStderr
	if err := cmdAliyun.Run(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Process JSON output with jq using direct argument passing (no shell)
	var jqStdout, jqStderr bytes.Buffer
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	cmdJq.Stdin = &aliyunStdout
	cmdJq.Stdout = &jqStdout
	cmdJq.Stderr = &jqStderr
	if err := cmdJq.Run(); err != nil {
		combinedErr := aliyunStderr.String() + jqStderr.String()
		return combinedErr, fmt.Errorf("jq command failed: %w", err)
	}

	// Write processed output to specified file
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644); err != nil {
		combinedErr := aliyunStderr.String() + jqStderr.String()
		return combinedErr, fmt.Errorf("failed to write output file: %w", err)
	}

	// Return combined stderr (may contain warnings) on success
	return aliyunStderr.String() + jqStderr.String(), nil
}

