	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmdAliyun.Stderr = &aliyunStderr

	// Configure jq command with exact filter from requirements
	cmdJq := exec.Command("jq", `.LoadBalancers.LoadBalancer[]`)
	cmdJq.Stdin = aliyunStdout
	cmdJq.Stdout = outFile
	cmdJq.Stderr = &jqStderr

