package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the jq command (processed output) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate outputFile is not empty (critical for file operations)
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Build aliyun command with explicit arguments (avoids shell injection)
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr

	// Build jq command with filter argument
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	var jqStderr bytes.Buffer
	cmdJq.Stderr = &jqStderr
	var jqOutput bytes.Buffer
	cmdJq.Stdout = &jqOutput

	// Connect aliyun stdout to jq stdin via pipe
	aliyunStdout, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun stdout: %w", err)
	}
	cmdJq.Stdin = aliyunStdout

	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := cmdJq.Start(); err != nil {
		cmdAliyun.Wait() // Clean up aliyun process on jq startup failure
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to complete (order matters: aliyun must finish to close pipe)
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// Prioritize aliyun errors (upstream failure)
	if errAliyun != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", errAliyun, aliyunStderr.String())
	}
	if errJq != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", errJq, jqStderr.String())
	}

	// Write processed output to specified file
	if err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file %q: %w", outputFile, err)
	}

	return jqOutput.String(), nil
}

