// Returns combined stderr output from both commands (if any) and any execution error.
// Security note: Avoids shell invocation entirely to prevent command injection.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Step 1: Execute aliyun CLI command with direct argument passing (no shell)
	var aliyunStdout, aliyunStderr bytes.Buffer
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
