	cmdJq.Stdout = &jqStdout
	cmdJq.Stderr = &jqStderr

	// Connect aliyun stdout to jq stdin via pipe
	aliyunOut, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmdJq.Stdin = aliyunOut

	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command; kill aliyun if jq fails to start
	if err := cmdJq.Start(); err != nil {
		if cmdAliyun.Process != nil {
			cmdAliyun.Process.Kill()
		}
		cmdAliyun.Wait() // Clean up aliyun resources
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

