	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// Check for command failures
	if errAliyun != nil || errJq != nil {
		var errMsg strings.Builder
		errMsg.WriteString("Command pipeline execution failed")

		if aliyunStderr.Len() > 0 {
			errMsg.WriteString("\naliyun stderr: ")
			errMsg.WriteString(aliyunStderr.String())
		}
		if jqStderr.Len() > 0 {
			errMsg.WriteString("\njq stderr: ")
			errMsg.WriteString(jqStderr.String())
		}
		if errAliyun != nil {
			errMsg.WriteString("\naliyun error: ")
			errMsg.WriteString(errAliyun.Error())
		}
		if errJq != nil && errJq != errAliyun {
			errMsg.WriteString("\njq error: ")
			errMsg.WriteString(errJq.Error())
